def normalize_price(value):
    if pd.isna(value) or value == '':
        return None

    # Convert to string and remove currency symbols/whitespace
    s = str(value).replace('$', '').strip()

    # Handle European format: 1.234,56 -> 1234.56
    # If there is a dot and a comma, and the comma comes last
    if '.' in s and ',' in s:
        if s.rfind(',') > s.rfind('.'):
            s = s.replace('.', '').replace(',', '.')
        else:
            s = s.replace(',', '')
    # If there is only a comma and it's used as a decimal (e.g., 1234,56)
    elif ',' in s:
        # If comma is 3rd from the end, it's likely a decimal separator
        if len(s.split(',')[-1]) <= 2:
            s = s.replace(',', '.')
        else:
            s = s.replace(',', '')

    try:
        return float(s)
    except ValueError:
        return None

def normalize_date(value):
    if pd.isna(value) or value == '':
        return None
    try:
        # dateutil.parser handles MM/DD/YYYY, YYYY-MM-DD, and 'January 5, 2024' automatically
        return parser.parse(str(value)).date().isoformat()
    except (ValueError, OverflowError):
        return None

def process_messy_csv(input_file, output_file):
    try:
        # sep=None with engine='python' tells pandas to guess the separator (comma or semicolon)
        # encoding_errors='replace' handles corrupted characters gracefully
        df = pd.read_csv(input_file, sep=None, engine='python', encoding_errors='replace')

        for col in df.columns:
            # Detect if column is likely a date
            sample = df[col].dropna().astype(str).head(5)
            if any(re.search(r'\d{1,4}[/-]\d{1,2}[/-]\d{1,4}|\d{1,2} \w+, \d{4}', s) for s in sample):
                df[col] = df[col].apply(normalize_date)

            # Detect if column is likely a price
            elif any(re.search(r'[\$\d][\d\.,]*', s) for s in sample):
                df[col] = df[col].apply(normalize_price)

        df.to_csv(output_file, index=False)
        print(f"Successfully processed. Saved to {output_file}")

    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    # Usage
    process_messy_csv('input.csv', 'cleaned_output.csv')
