import csv
import re
from dateutil import parser # Third party library for flexible date parsing

def normalize_price(value):
    """
    Normalizes prices from various formats ($1,234.56, 1.234,56, etc.) to float.
    """
    if not value or value.strip() == "":
        return None

    # Remove currency symbols and whitespace
    clean_val = re.sub(r'[^\d own,.]', '', value).strip()

    if not clean_val:
        return None

    # Case 1: Contains both dot and comma (e.g., 1,234.56 or 1.234,56)
    if ',' in clean_val and '.' in clean_val:
        if clean_val.rfind(',') > clean_val.rfind('.'):
            # European style: 1.234,56 -> 1234.56
            clean_val = clean_val.replace('.', '').replace(',', '.')
        else:
            # US style: 1,234.56 -> 1234.56
            clean_val = clean_val.replace(',', '')

    # Case 2: Contains only comma (e.g., 1,234 or 12,50)
    elif ',' in clean_val:
        # Heuristic: If comma is followed by exactly 2 digits, assume it's a decimal
        if len(clean_val) - clean_val.rfind(',') == 3:
            clean_val = clean_val.replace(',', '.')
        else:
            # Assume it's a thousands separator
            clean_val = clean_val.replace(',', '')

    # Case 3: Contains only dot (e.g., 1.234)
    # This is the most ambiguous case. We assume standard float.

    try:
        return float(clean_val)
    except ValueError:
        return None

def normalize_date(value):
    """
    Normalizes various date strings to ISO format (YYYY-MM-DD).
    """
    if not value or value.strip() == "":
        return None
    try:
        # dateutil.parser can handle MM/DD/YYYY, YYYY-MM-DD, and "January 5, 2024"
        return parser.parse(value).date().isoformat()
    except (ValueError, OverflowError):
        return None

